#include <Servo.h>
#include <ArduinoJson.h>

#if defined(ESP32)
#include <WiFi.h>
#include <WebServer.h>
#endif

// Servo Configuration
#define SERVO_PIN {{.servoPin}}
#define FEEDBACK_PIN {{.feedbackPin}}
#define MIN_ANGLE {{.minAngle}}
#define MAX_ANGLE {{.maxAngle}}
#define MOVEMENT_SPEED {{.speed}} // 1=slowest, 10=fastest
#define ENABLE_FEEDBACK {{.enableFeedback}}

// WiFi Configuration (ESP32 only)
#if defined(ESP32)
const char* ssid = "{{.ssid}}";
const char* password = "{{.password}}";
const char* deviceName = "{{.deviceName}}";
WebServer server(80);
#endif

// Global variables
Servo myServo;
int currentAngle = 90;
int targetAngle = 90;
int feedbackAngle = 90;
bool isMoving = false;
unsigned long lastMoveTime = 0;
int moveStep = 0;

// Preset positions
const char* presetNames[] = {"Home", "Left", "Right", "Center"};
const int presetAngles[] = {90, {{.minAngle}}, {{.maxAngle}}, 90};
const int numPresets = 4;

// Function prototypes
void setupServo();
void moveServoToAngle(int angle);
int readFeedback();
void updatePosition();
#if defined(ESP32)
void setupWiFi();
void setupWebServer();
void handleRoot();
void handleControl();
void handleStatus();
void handlePresets();
String getHTMLHeader();
String getHTMLFooter();
String getControlPanel();
String getPresetButtons();
String getJavaScript();
String getCSS();
#endif

void setup() {
  Serial.begin(115200);
  Serial.println("Servo Motor Control with Position Feedback Starting...");

  setupServo();

#if defined(ESP32)
  setupWiFi();
  setupWebServer();
  Serial.print("Web server started! IP: ");
  Serial.println(WiFi.localIP());
#endif

  Serial.println("Setup completed!");
}

void setupServo() {
  myServo.attach(SERVO_PIN);

  // Move to initial position
  moveServoToAngle(90);
  delay(1000);

  Serial.print("Servo initialized - Range: ");
  Serial.print(MIN_ANGLE);
  Serial.print("° to ");
  Serial.print(MAX_ANGLE);
  Serial.println("°");

  if (ENABLE_FEEDBACK) {
    Serial.print("Position feedback enabled on pin A");
    Serial.println(FEEDBACK_PIN);
  } else {
    Serial.println("Position feedback disabled");
  }
}

#if defined(ESP32)
void setupWiFi() {
  Serial.println("Connecting to WiFi...");

  WiFi.begin(ssid, password);

  int attempts = 0;
  while (WiFi.status() != WL_CONNECTED && attempts < 20) {
    delay(500);
    Serial.print(".");
    attempts++;
  }

  if (WiFi.status() == WL_CONNECTED) {
    Serial.println("");
    Serial.println("WiFi connected!");
    Serial.print("IP address: ");
    Serial.println(WiFi.localIP());
  } else {
    Serial.println("Failed to connect to WiFi");
  }
}

void setupWebServer() {
  server.on("/", HTTP_GET, handleRoot);
  server.on("/control", HTTP_POST, handleControl);
  server.on("/status", HTTP_GET, handleStatus);
  server.on("/presets", HTTP_GET, handlePresets);

  server.on("/style.css", []() {
    server.send(200, "text/css", getCSS());
  });

  server.on("/script.js", []() {
    server.send(200, "application/javascript", getJavaScript());
  });

  server.begin();
}
#endif

void loop() {
#if defined(ESP32)
  server.handleClient();
#endif

  updatePosition();

  // Print status every 5 seconds
  static unsigned long lastStatusTime = 0;
  if (millis() - lastStatusTime >= 5000) {
    lastStatusTime = millis();
    printStatus();
  }

  delay(50);
}

void moveServoToAngle(int angle) {
  // Constrain angle to valid range
  if (angle < MIN_ANGLE) angle = MIN_ANGLE;
  if (angle > MAX_ANGLE) angle = MAX_ANGLE;

  targetAngle = angle;
  isMoving = true;
  lastMoveTime = millis();

  // Calculate step size based on speed
  moveStep = max(1, 10 - MOVEMENT_SPEED);

  Serial.print("Moving servo to ");
  Serial.print(angle);
  Serial.println("°");
}

void updatePosition() {
  if (!isMoving) return;

  unsigned long currentTime = millis();

  // Move servo gradually based on speed setting
  if (currentTime - lastMoveTime >= (50 / MOVEMENT_SPEED)) {
    lastMoveTime = currentTime;

    if (currentAngle < targetAngle) {
      currentAngle += moveStep;
      if (currentAngle > targetAngle) {
        currentAngle = targetAngle;
      }
    } else if (currentAngle > targetAngle) {
      currentAngle -= moveStep;
      if (currentAngle < targetAngle) {
        currentAngle = targetAngle;
      }
    }

    // Update servo position
    int servoAngle = map(currentAngle, MIN_ANGLE, MAX_ANGLE, 0, 180);
    myServo.write(servoAngle);

    // Check if movement is complete
    if (currentAngle == targetAngle) {
      isMoving = false;
      Serial.print("Servo reached target: ");
      Serial.print(currentAngle);
      Serial.println("°");
    }
  }
}

int readFeedback() {
  if (!ENABLE_FEEDBACK) {
    return currentAngle; // Return target if feedback disabled
  }

  // Read potentiometer value
  int rawValue = analogRead(FEEDBACK_PIN);

  // Map to angle range (assuming 10k potentiometer)
  int angle = map(rawValue, 0, 1023, MIN_ANGLE, MAX_ANGLE);

  // Constrain to valid range
  if (angle < MIN_ANGLE) angle = MIN_ANGLE;
  if (angle > MAX_ANGLE) angle = MAX_ANGLE;

  return angle;
}

void printStatus() {
  feedbackAngle = readFeedback();

  Serial.print("Status - Target: ");
  Serial.print(targetAngle);
  Serial.print("°, Current: ");
  Serial.print(currentAngle);
  Serial.print("°");

  if (ENABLE_FEEDBACK) {
    Serial.print(", Feedback: ");
    Serial.print(feedbackAngle);
    Serial.print("°");

    int error = abs(currentAngle - feedbackAngle);
    Serial.print(", Error: ");
    Serial.print(error);
    Serial.println("°");
  } else {
    Serial.println();
  }
}

#if defined(ESP32)
void handleRoot() {
  String html = getHTMLHeader();
  html += getControlPanel();
  html += getHTMLFooter();
  server.send(200, "text/html", html);
}

void handleControl() {
  String angleStr = server.arg("angle");
  String speedStr = server.arg("speed");

  if (angleStr.length() > 0) {
    int angle = angleStr.toInt();

    if (speedStr.length() > 0) {
      int speed = speedStr.toInt();
      if (speed >= 1 && speed <= 10) {
        MOVEMENT_SPEED = speed;
      }
    }

    moveServoToAngle(angle);

    // Send JSON response
    StaticJsonDocument<200> doc;
    doc["success"] = true;
    doc["targetAngle"] = targetAngle;
    doc["currentAngle"] = currentAngle;
    doc["isMoving"] = isMoving;
    doc["speed"] = MOVEMENT_SPEED;

    if (ENABLE_FEEDBACK) {
      doc["feedbackAngle"] = readFeedback();
    }

    String response;
    serializeJson(doc, response);
    server.send(200, "application/json", response);
    return;
  }

  // Error response
  StaticJsonDocument<100> doc;
  doc["success"] = false;
  doc["error"] = "Invalid angle parameter";

  String response;
  serializeJson(doc, response);
  server.send(400, "application/json", response);
}

void handleStatus() {
  StaticJsonDocument<300> doc;
  doc["deviceName"] = deviceName;
  doc["targetAngle"] = targetAngle;
  doc["currentAngle"] = currentAngle;
  doc["isMoving"] = isMoving;
  doc["minAngle"] = MIN_ANGLE;
  doc["maxAngle"] = MAX_ANGLE;
  doc["speed"] = MOVEMENT_SPEED;
  doc["enableFeedback"] = ENABLE_FEEDBACK;
  doc["uptime"] = millis();

  if (ENABLE_FEEDBACK) {
    doc["feedbackAngle"] = readFeedback();
    doc["positionError"] = abs(currentAngle - readFeedback());
  }

  // Add presets
  JsonArray presets = doc.createNestedArray("presets");
  for (int i = 0; i < numPresets; i++) {
    JsonObject preset = presets.createNestedObject();
    preset["name"] = presetNames[i];
    preset["angle"] = presetAngles[i];
  }

  String response;
  serializeJson(doc, response);
  server.send(200, "application/json", response);
}

void handlePresets() {
  StaticJsonDocument<200> doc;
  JsonArray presets = doc.createNestedArray("presets");

  for (int i = 0; i < numPresets; i++) {
    JsonObject preset = presets.createNestedObject();
    preset["id"] = i;
    preset["name"] = presetNames[i];
    preset["angle"] = presetAngles[i];
  }

  String response;
  serializeJson(doc, response);
  server.send(200, "application/json", response);
}

String getHTMLHeader() {
  return R"(<!DOCTYPE html>
<html>
<head>
    <meta charset="UTF-8">
    <meta name="viewport" content="width=device-width, initial-scale=1.0">
    <title>)" + String(deviceName) + R"(</title>
    <link rel="stylesheet" href="/style.css">
</head>
<body>)";
}

String getHTMLFooter() {
  return R"(</body>
<script src="/script.js"></script>
</html>)";
}

String getControlPanel() {
  String panel = R"(<div class='container'>
    <h1>)" + String(deviceName) + R"(</h1>

    <div class='status-panel'>
        <div class='status-item'>
            <span class='label'>Target Angle:</span>
            <span class='value' id='target-angle'>90°</span>
        </div>
        <div class='status-item'>
            <span class='label'>Current Angle:</span>
            <span class='value' id='current-angle'>90°</span>
        </div>)";

  if (ENABLE_FEEDBACK) {
    panel += R"(<div class='status-item'>
            <span class='label'>Feedback Angle:</span>
            <span class='value' id='feedback-angle'>90°</span>
        </div>
        <div class='status-item'>
            <span class='label'>Position Error:</span>
            <span class='value' id='position-error'>0°</span>
        </div>)";
  }

  panel += R"(<div class='status-item'>
            <span class='label'>Movement Status:</span>
            <span class='value' id='movement-status'>Idle</span>
        </div>
    </div>

    <div class='control-panel'>
        <h2>Servo Control</h2>

        <div class='angle-control'>
            <label for='angle-slider'>Angle: <span id='angle-value'>90</span>°</label>
            <input type='range' id='angle-slider' min=')" + String(MIN_ANGLE) + R"(' max=')" + String(MAX_ANGLE) + R"(' value='90' class='slider'>
        </div>

        <div class='speed-control'>
            <label for='speed-slider'>Speed: <span id='speed-value'>5</span></label>
            <input type='range' id='speed-slider' min='1' max='10' value='5' class='slider'>
        </div>

        <div class='preset-buttons'>)";

  panel += getPresetButtons();

  panel += R"(</div>

    <div class='info-panel'>
        <h3>System Information</h3>
        <div class='info-item'>
            <span class='label'>Angle Range:</span>
            <span class='value'>)" + String(MIN_ANGLE) + R"(° to )" + String(MAX_ANGLE) + R"(°</span>
        </div>
        <div class='info-item'>
            <span class='label'>Position Feedback:</span>
            <span class='value'>)" + String(ENABLE_FEEDBACK ? "Enabled" : "Disabled") + R"(</span>
        </div>
    </div>
</div>)";

  return panel;
}

String getPresetButtons() {
  String buttons = "";

  for (int i = 0; i < numPresets; i++) {
    buttons += "<button class='preset-btn' onclick='moveToPreset(" + String(i) + ", " + String(presetAngles[i]) + ")'>";
    buttons += presetNames[i];
    buttons += "</button>";
  }

  return buttons;
}

String getJavaScript() {
  return R"(let targetAngle = 90;
let currentAngle = 90;
let isMoving = false;

function updateStatus() {
  fetch('/status')
    .then(response => response.json())
    .then(data => {
      targetAngle = data.targetAngle;
      currentAngle = data.currentAngle;
      isMoving = data.isMoving;

      document.getElementById('target-angle').textContent = targetAngle + '°';
      document.getElementById('current-angle').textContent = currentAngle + '°';
      document.getElementById('movement-status').textContent = isMoving ? 'Moving' : 'Idle';

      if (data.enableFeedback) {
        document.getElementById('feedback-angle').textContent = data.feedbackAngle + '°';
        document.getElementById('position-error').textContent = data.positionError + '°';
      }

      document.getElementById('angle-slider').value = targetAngle;
      document.getElementById('angle-value').textContent = targetAngle;
      document.getElementById('speed-slider').value = data.speed;
      document.getElementById('speed-value').textContent = data.speed;
    })
    .catch(error => console.error('Status update error:', error));
}

function moveToAngle(angle) {
  const speed = document.getElementById('speed-slider').value;

  fetch('/control', {
    method: 'POST',
    headers: {
      'Content-Type': 'application/x-www-form-urlencoded',
    },
    body: 'angle=' + angle + '&speed=' + speed
  })
  .then(response => response.json())
  .then(data => {
    if (data.success) {
      updateStatus();
    } else {
      console.error('Error:', data.error);
    }
  })
  .catch(error => console.error('Control error:', error));
}

function moveToPreset(presetId, angle) {
  moveToAngle(angle);
}

// Event listeners
document.getElementById('angle-slider').addEventListener('input', function(e) {
  const angle = parseInt(e.target.value);
  document.getElementById('angle-value').textContent = angle;
  moveToAngle(angle);
});

document.getElementById('speed-slider').addEventListener('input', function(e) {
  const speed = parseInt(e.target.value);
  document.getElementById('speed-value').textContent = speed;
});

// Auto-update status every second
setInterval(updateStatus, 1000);)";
}

String getCSS() {
  return R"(* {
    margin: 0;
    padding: 0;
    box-sizing: border-box;
  }

  body {
    font-family: 'Segoe UI', Tahoma, Geneva, Verdana, sans-serif;
    background: linear-gradient(135deg, #667eea 0%, #764ba2 100%);
    min-height: 100vh;
    color: #333;
  }

  .container {
    max-width: 800px;
    margin: 0 auto;
    padding: 20px;
  }

  h1 {
    text-align: center;
    color: white;
    margin-bottom: 30px;
    text-shadow: 2px 2px 4px rgba(0,0,0,0.3);
  }

  .status-panel {
    background: white;
    border-radius: 15px;
    padding: 20px;
    margin-bottom: 20px;
    box-shadow: 0 8px 32px rgba(0,0,0,0.1);
    display: grid;
    grid-template-columns: repeat(auto-fit, minmax(200px, 1fr));
    gap: 15px;
  }

  .status-item {
    display: flex;
    justify-content: space-between;
    align-items: center;
  }

  .label {
    font-weight: 600;
    color: #666;
  }

  .value {
    font-weight: bold;
    color: #333;
    padding: 4px 8px;
    background: #f0f0f0;
    border-radius: 4px;
  }

  .control-panel {
    background: white;
    border-radius: 15px;
    padding: 25px;
    margin-bottom: 20px;
    box-shadow: 0 8px 32px rgba(0,0,0,0.1);
  }

  .control-panel h2 {
    margin-top: 0;
    color: #333;
  }

  .angle-control, .speed-control {
    margin-bottom: 20px;
  }

  .angle-control label, .speed-control label {
    display: block;
    margin-bottom: 10px;
    font-weight: 600;
    color: #666;
  }

  .slider {
    width: 100%;
    height: 8px;
    border-radius: 4px;
    background: #ddd;
    outline: none;
    -webkit-appearance: none;
  }

  .slider::-webkit-slider-thumb {
    -webkit-appearance: none;
    appearance: none;
    width: 24px;
    height: 24px;
    border-radius: 50%;
    background: #667eea;
    cursor: pointer;
  }

  .slider::-moz-range-thumb {
    width: 24px;
    height: 24px;
    border-radius: 50%;
    background: #667eea;
    cursor: pointer;
    border: none;
  }

  .preset-buttons {
    display: flex;
    gap: 10px;
    flex-wrap: wrap;
  }

  .preset-btn {
    flex: 1;
    min-width: 100px;
    padding: 12px 20px;
    border: none;
    border-radius: 8px;
    background: #667eea;
    color: white;
    font-weight: bold;
    cursor: pointer;
    transition: all 0.3s ease;
  }

  .preset-btn:hover {
    background: #5a67d8;
    transform: scale(1.05);
  }

  .info-panel {
    background: white;
    border-radius: 15px;
    padding: 20px;
    box-shadow: 0 8px 32px rgba(0,0,0,0.1);
  }

  .info-panel h3 {
    margin-top: 0;
    color: #333;
  }

  .info-item {
    display: flex;
    justify-content: space-between;
    margin-bottom: 10px;
  }
})";
}
#endif
